import React from "react";
import "./Result.css";

const INDUSTRY_ICONS = {
    "Công nghệ thông tin": "💻",
    "Quản trị kinh doanh": "📊",
    "Marketing": "📣",
    "Tài chính - Kế toán": "💰",
    "Nhân sự": "👥",
    "Thiết kế": "🎨",
    "Logistics": "🚚",
    "Giáo dục": "🎓",
};

const getIcon = (industry) => INDUSTRY_ICONS[industry] || "📁";

const ConfidenceBar = ({ label, value, isTop }) => (
    <div className={`prob-row ${isTop ? "top" : ""}`}>
        <div className="prob-label">
            <span className="prob-icon">{getIcon(label)}</span>
            <span className="prob-name">{label}</span>
        </div>
        <div className="prob-bar-wrap">
            <div
                className="prob-bar-fill"
                style={{ width: `${(value * 100).toFixed(1)}%` }}
            />
        </div>
        <span className="prob-pct">{(value * 100).toFixed(1)}%</span>
    </div>
);

const Result = ({ data }) => {
    if (!data) return null;

    const { predicted_industry, confidence, probabilities } = data;
    const confidencePct = (confidence * 100).toFixed(1);
    const sortedProbs = Object.entries(probabilities).sort((a, b) => b[1] - a[1]);

    const confidenceClass =
        confidence >= 0.7 ? "high" : confidence >= 0.4 ? "medium" : "low";

    return (
        <div className="result-card">
            {/* Header */}
            <div className="result-header">
                <span className="result-check">✅</span>
                <h2 className="result-title">Kết quả phân tích</h2>
            </div>

            {/* Main Prediction */}
            <div className={`prediction-box ${confidenceClass}`}>
                <div className="prediction-icon">{getIcon(predicted_industry)}</div>
                <div className="prediction-info">
                    <p className="prediction-label">Ngành nghề phù hợp</p>
                    <h3 className="prediction-value">{predicted_industry}</h3>
                </div>
                <div className={`confidence-badge ${confidenceClass}`}>
                    {confidencePct}%
                </div>
            </div>

            {/* Confidence Meter */}
            <div className="confidence-section">
                <div className="section-label">Độ tin cậy</div>
                <div className="confidence-track">
                    <div
                        className={`confidence-fill ${confidenceClass}`}
                        style={{ width: `${confidencePct}%` }}
                    />
                </div>
                <span className={`confidence-text ${confidenceClass}`}>
                    {confidence >= 0.7 ? "Cao" : confidence >= 0.4 ? "Trung bình" : "Thấp"}
                </span>
            </div>

            {/* Probability Breakdown */}
            <div className="probabilities-section">
                <div className="section-label">Phân tích theo ngành</div>
                <div className="prob-list">
                    {sortedProbs.map(([label, value], idx) => (
                        <ConfidenceBar
                            key={label}
                            label={label}
                            value={value}
                            isTop={idx === 0}
                        />
                    ))}
                </div>
            </div>
        </div>
    );
};

export default Result;
